css:
.loader {
  display: grid;
  gap: 10px;
  width: 138px;
}
.loader i {
  display: block;
  height: 12px;
  border-radius: 999px;
  background: linear-gradient(90deg, rgba(99,102,241,.12), rgba(99,102,241,.32), rgba(99,102,241,.12));
  background-size: 220% 100%;
  animation: shimmer 1.1s linear infinite;
}
.loader i:nth-child(2) { width: 82%; }
.loader i:nth-child(3) { width: 58%; }
@keyframes shimmer {
  to { background-position: -220% 0; }
}
